          "code": "\n\"\"\"\nGiven an unsorted array of integers nums, return the length of\nthe longest consecutive elements sequence.\nYou must write an algorithm that runs in O(n) time.\n\nExample 1:\n\nInput: nums = [100,4,200,1,3,2]\nOutput: 4\nExplanation: The longest consecutive elements sequence is\n[1, 2, 3, 4]. Therefore its length is 4.\nExample 2:\n\nInput: nums = [0,3,7,2,5,8,4,6,0,1]\nOutput: 9\nExample 3:\n\nInput: nums = [1,0,1,2]\nOutput: 3\n\"\"\"\n\nfrom typing import List\n\n\nclass Solution:\n    \"\"\"\n    Time complexity:  O(n) -- each number is the start of at most one streak,\n                      and the inner while-loop walks each value at most once.\n    Space complexity: O(n) -- the hash set stores every distinct number.\n    \"\"\"\n\n    def longestConsecutiveSequence(self, nums: List[int]) -> int:\n        num_set = set(nums)\n        longest_streak = 0\n\n        for num in nums:\n            if num - 1 not in num_set:\n                current_num = num\n                current_streak = 1\n\n                while current_num + 1 in num_set:\n                    current_num += 1\n                    current_streak += 1\n\n                longest_streak = max(longest_streak, current_streak)\n        return longest_streak\n\n\nif __name__ == '__main__':\n    solution = Solution()\n    # print(solution.longestConsecutiveSequence([100,4,200,1,3,2]))\n    print(solution.longestConsecutiveSequence([0, 3, 7, 2, 5, 8, 4, 6, 0, 1]))\n"
