          "lang": "python",
          "label": "Python — BFS, DFS (rec & iter)",
          "path": "python/graphs/graph_traversal.py",
          "code": "\nfrom collections import deque\n\nclass GraphBFS:\n    \"\"\"\n    BFS and DFS traversals over an adjacency-list graph.\n\n    For each traversal (bfs / dfs_recursive / dfs_iterative):\n      Time complexity:  O(V + E) -- every vertex and edge is visited once.\n      Space complexity: O(V) -- visited set plus the queue / stack\n                        (recursion stack for dfs_recursive).\n    \"\"\"\n\n    def bfs(self, graph: dict[int, list[int]], start_node: int) -> list:\n\n        visited_node = {start_node}\n        queue = deque([start_node]) \n        visit_order = []\n        while queue:\n            current_node = queue.popleft()\n            visit_order.append(current_node)\n            for neighbour in graph.get(current_node, []):\n                if neighbour not in visited_node:\n                    visited_node.add(neighbour)\n                    queue.append(neighbour)\n        return visit_order\n\n    def dfs_recursive(self, graph: dict[int, list[int]], current_node: int, visited_node: set[int]) -> None:\n        visited_node.add(current_node)\n        print(current_node)\n        for neighbour in graph[current_node]:\n            if neighbour not in visited_node:\n                self.dfs_recursive(graph, neighbour, visited_node)\n\n    def dfs_iterative(self, graph: dict[int, list[int]], start_node: int) -> list:\n        visited_node = {start_node}\n        stack = [start_node]\n        visit_order = []\n\n        while stack:\n            current_node = stack.pop()\n            visit_order.append(current_node)\n\n            for neighbour in graph[current_node]:\n                if neighbour not in visited_node:\n                    visited_node.add(neighbour)\n                    stack.append(neighbour)\n        return visit_order\n\nif __name__ == '__main__':\n    example_graph = {\n        'A': ['B', 'C'],\n        'B': ['A', 'D', 'E'],\n        'C': ['A', 'F'],\n        'D': ['B'],\n        'E': ['B', 'F'],\n        'F': ['C', 'E']\n    }\n\n    graph_bfs = GraphBFS()\n    print(graph_bfs.bfs(example_graph, 'B'))\n    graph_bfs.dfs_recursive(example_graph, 'B', set())\n    print(graph_bfs.dfs_iterative(example_graph, 'B'))\n"
