          "path": "python/graphs/cycle_detect_directed_graph.py",
          "code": "\nfrom typing import List\nfrom collections import defaultdict, deque\n\nclass Solution:\n\n\tdef detect_cycle_directed_graph(self, vertices: int, adj: List[List[int]]):\n\t\t\"\"\"\n\t\tKahn's algorithm: if a topological sort cannot process every vertex,\n\t\tthe leftover vertices form a cycle.\n\n\t\tTime complexity:  O(V + E) -- each vertex and edge is visited once.\n\t\tSpace complexity: O(V + E) -- adjacency map, in-degree array, and queue.\n\t\t\"\"\"\n\t\tindegree = [0] * vertices\n\t\tgraph = defaultdict(list)\n\n\t\tfor u in range(vertices):\n\t\t\tfor v in adj[u]:\n\t\t\t\tgraph[u].append(v)\n\t\t\t\tindegree[v] += 1\n\n\t\t# queue for maintaining vertices which doesn't have dependencies and can be processed early\n\t\tqueue: deque = deque(i for i in range(vertices) if indegree[i] == 0)\n\t\tprocessed: int = 0\n\n\t\twhile queue:\n\t\t\tnode = queue.popleft()\n\t\t\tprocessed += 1\n\n\t\t\tfor neighbour in graph[node]:\n\t\t\t\tindegree[neighbour] -= 1\n\t\t\t\tif indegree[neighbour] == 0:\n\t\t\t\t\tqueue.append(neighbour)\n\n\t\treturn processed != vertices\n\n\nif __name__ == '__main__':\n\tsolution = Solution()\n\t# 0 -> 1 -> 2 -> 0  (cycle)\n\tprint(solution.detect_cycle_directed_graph(3, [[1], [2], [0]]))   # True\n\t# 0 -> 1 -> 2  (DAG, no cycle)\n\tprint(solution.detect_cycle_directed_graph(3, [[1, 2], [2], []]))  # False\n\n\n\n"
